import React, { useState, useEffect } from 'react';
import api from '../../services/api';

export default function StatusTracker({ appTheme, isMobile }) {
    const isDark = appTheme === 'dark';

    const [applications, setApplications] = useState([
        { id_lamaran: 'APP-001', title: 'Fullstack Developer', company: 'PasukanYerusSolo', applied_date: '2026-05-28', status: 'Diproses', pesan_hrd: 'Berkas CV Anda sedang ditinjau.' },
        { id_lamaran: 'APP-002', title: 'React Frontend Engineer', company: 'TechEase Indonesia', applied_date: '2026-05-15', status: 'Diterima', pesan_hrd: 'Selamat! Anda diundang interview.' }
    ]);

    const colors = {
        cardBg: '#171717',
        border: '#262626',
        textMain: '#ffffff',
        textMuted: '#a3a3a3',
        accent: '#f59e0b'
    };

    return (
        /* Container utama dengan padding agar tidak menempel ke sidebar */
        <div style={{ 
            padding: '32px 40px', 
            maxWidth: '1000px', // Membatasi lebar agar tetap proporsional
            margin: '0 auto',   // Menjaga konten tetap di tengah
            width: '100%'
        }}>
            <h2 style={{ color: '#fff', marginBottom: '24px' }}>Status Lamaran Saya</h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {applications.map((app) => {
                    const badge = {
                        bg: app.status === 'Diterima' ? '#064e3b' : '#431407',
                        text: app.status === 'Diterima' ? '#34d399' : '#fb923c',
                        label: app.status
                    };

                    return (
                        <div key={app.id_lamaran} style={{ 
                            background: colors.cardBg,
                            border: `1px solid ${colors.border}`,
                            borderRadius: '16px',
                            padding: '24px',
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            transition: 'transform 0.2s'
                        }}>
                            <div style={{ flex: 1 }}>
                                <h3 style={{ margin: '0 0 4px 0', color: colors.textMain }}>{app.title}</h3>
                                <p style={{ margin: '0 0 12px 0', color: colors.accent, fontWeight: '600' }}>{app.company}</p>
                                <p style={{ margin: '0', fontSize: '13px', color: colors.textMuted }}>
                                    📅 Melamar pada: {app.applied_date}
                                </p>
                                {app.pesan_hrd && (
                                    <div style={{ marginTop: '12px', fontSize: '13px', color: colors.textMuted, fontStyle: 'italic' }}>
                                        <strong>Catatan HRD:</strong> {app.pesan_hrd}
                                    </div>
                                )}
                            </div>

                            <div style={{
                                background: badge.bg,
                                color: badge.text,
                                padding: '8px 20px',
                                borderRadius: '30px',
                                fontWeight: '700',
                                fontSize: '12px',
                                marginLeft: '24px'
                            }}>
                                {badge.label}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
